```class Solution {
public:
    string minWindow(string s, string t) {
        if (s.empty() || t.empty()) return "";
        unordered_map<char, int> tCount, windowCount;
        for (char c : t) tCount[c]++;
        int required = tCount.size(), formed = 0;
        int windowCounts[2] = {0, 0}, minLen = INT_MAX, minLeft = 0, minRight = 0;
        int left = 0, right = 0;
        while (right < s.length()) {
            char character = s[right];
            windowCount[character]++;
            if (tCount.find(character) != tCount.end() && tCount[character] == windowCount[character])
                formed++;
            while (left <= right && formed == required) {
                character = s[left];
                if (right - left + 1 < minLen) {
                    minLen = right - left + 1;
                    minLeft = left;
                    minRight = right;
                }
                windowCount[character]--;
                if (tCount.find(character) != tCount.end() && tCount[character] > windowCount[character])
                    formed--;
                left++; 
            }
            right++; 
        }
        return minLen == INT_MAX ? "" : s.substr(minLeft, minRight - minLeft + 1);
    }
};
